import{_ as e,o as s,c as i,ag as n}from"./chunks/framework.CTpQozEL.js";const k=JSON.parse('{"title":"메시지","description":"메시지 흐름, 세션, 큐잉, 추론 가시성","frontmatter":{"title":"메시지","description":"메시지 흐름, 세션, 큐잉, 추론 가시성"},"headers":[],"relativePath":"concepts/messages.md","filePath":"concepts/messages.md","lastUpdated":null}'),l={name:"concepts/messages.md"};function o(t,a,c,p,d,h){return s(),i("div",null,[...a[0]||(a[0]=[n(`<h1 id="메시지" tabindex="-1">메시지 <a class="header-anchor" href="#메시지" aria-label="Permalink to &quot;메시지&quot;">​</a></h1><p>이 페이지는 OpenClaw가 인바운드 메시지, 세션, 큐잉, 스트리밍, 추론 가시성을 처리하는 방법을 연결합니다.</p><h2 id="메시지-흐름-상위-수준" tabindex="-1">메시지 흐름 (상위 수준) <a class="header-anchor" href="#메시지-흐름-상위-수준" aria-label="Permalink to &quot;메시지 흐름 (상위 수준)&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>인바운드 메시지</span></span>
<span class="line"><span>  -&gt; 라우팅/바인딩 -&gt; 세션 키</span></span>
<span class="line"><span>  -&gt; 큐 (실행이 활성 상태인 경우)</span></span>
<span class="line"><span>  -&gt; 에이전트 실행 (스트리밍 + 도구)</span></span>
<span class="line"><span>  -&gt; 아웃바운드 응답 (채널 한도 + 청킹)</span></span></code></pre></div><p>주요 설정은 구성에 있습니다:</p><ul><li>접두사, 큐잉, 그룹 동작은 <code>messages.*</code>.</li><li>블록 스트리밍 및 청킹 기본값은 <code>agents.defaults.*</code>.</li><li>채널 오버라이드 (<code>channels.whatsapp.*</code>, <code>channels.telegram.*</code> 등)는 상한 및 스트리밍 토글.</li></ul><p>전체 스키마는 <a href="/openclaw-docs-ko/gateway/configuration">구성</a>을 참조하십시오.</p><h2 id="인바운드-중복-제거" tabindex="-1">인바운드 중복 제거 <a class="header-anchor" href="#인바운드-중복-제거" aria-label="Permalink to &quot;인바운드 중복 제거&quot;">​</a></h2><p>채널은 재연결 후 동일한 메시지를 다시 전달할 수 있습니다. OpenClaw는 채널/계정/피어/세션/메시지 ID로 키가 지정된 단기 캐시를 유지하여 중복 전달이 다른 에이전트 실행을 트리거하지 않도록 합니다.</p><h2 id="인바운드-디바운싱" tabindex="-1">인바운드 디바운싱 <a class="header-anchor" href="#인바운드-디바운싱" aria-label="Permalink to &quot;인바운드 디바운싱&quot;">​</a></h2><p><strong>동일 발신자</strong>의 빠른 연속 메시지는 <code>messages.inbound</code>를 통해 단일 에이전트 턴으로 배치될 수 있습니다. 디바운싱은 채널 + 대화별로 범위가 지정되며 응답 스레딩/ID에 가장 최근 메시지를 사용합니다.</p><p>구성 (전역 기본값 + 채널별 오버라이드):</p><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  messages</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    inbound</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      debounceMs</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      byChannel</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        whatsapp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">5000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        slack</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1500</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        discord</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1500</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>참고:</p><ul><li>디바운스는 <strong>텍스트 전용</strong> 메시지에 적용됩니다; 미디어/첨부파일은 즉시 플러시됩니다.</li><li>제어 커맨드는 독립 실행형으로 유지되도록 디바운싱을 우회합니다.</li></ul><h2 id="세션-및-장치" tabindex="-1">세션 및 장치 <a class="header-anchor" href="#세션-및-장치" aria-label="Permalink to &quot;세션 및 장치&quot;">​</a></h2><p>세션은 클라이언트가 아닌 게이트웨이가 소유합니다.</p><ul><li>직접 채팅은 에이전트 메인 세션 키로 통합됩니다.</li><li>그룹/채널은 자체 세션 키를 갖습니다.</li><li>세션 저장소와 트랜스크립트는 게이트웨이 호스트에 있습니다.</li></ul><p>여러 장치/채널이 동일한 세션에 매핑될 수 있지만, 히스토리는 모든 클라이언트에게 완전히 동기화되지 않습니다. 권장 사항: 발산하는 컨텍스트를 방지하기 위해 긴 대화에는 하나의 기본 장치를 사용하십시오. 제어 UI와 TUI는 항상 게이트웨이 지원 세션 트랜스크립트를 표시하므로 이들이 진실의 소스입니다.</p><p>세부사항: <a href="/openclaw-docs-ko/concepts/session">세션 관리</a>.</p><h2 id="인바운드-본문-및-히스토리-컨텍스트" tabindex="-1">인바운드 본문 및 히스토리 컨텍스트 <a class="header-anchor" href="#인바운드-본문-및-히스토리-컨텍스트" aria-label="Permalink to &quot;인바운드 본문 및 히스토리 컨텍스트&quot;">​</a></h2><p>OpenClaw는 <strong>프롬프트 본문</strong>과 <strong>커맨드 본문</strong>을 분리합니다:</p><ul><li><code>Body</code>: 에이전트에 전송되는 프롬프트 텍스트. 채널 봉투 및 선택적 히스토리 래퍼를 포함할 수 있습니다.</li><li><code>CommandBody</code>: 지시어/커맨드 파싱을 위한 원시 사용자 텍스트.</li><li><code>RawBody</code>: <code>CommandBody</code>의 레거시 별칭 (호환성을 위해 유지).</li></ul><p>채널이 히스토리를 제공할 때, 공유 래퍼를 사용합니다:</p><ul><li><code>[Chat messages since your last reply - for context]</code></li><li><code>[Current message - respond to this]</code></li></ul><p><strong>비직접 채팅</strong> (그룹/채널/룸)의 경우, <strong>현재 메시지 본문</strong> 앞에 발신자 레이블이 붙습니다 (히스토리 항목에 사용되는 것과 동일한 스타일). 이는 실시간 및 큐에 대기 중인/히스토리 메시지가 에이전트 프롬프트에서 일관되게 유지됩니다.</p><p>히스토리 버퍼는 <strong>보류 전용</strong>입니다: 실행을 트리거하지 않은 그룹 메시지 (예: 멘션 게이팅 메시지)를 포함하고 세션 트랜스크립트에 이미 있는 메시지는 <strong>제외</strong>합니다.</p><p>지시어 제거는 히스토리가 그대로 유지되도록 <strong>현재 메시지</strong> 섹션에만 적용됩니다. 히스토리를 래핑하는 채널은 <code>CommandBody</code> (또는 <code>RawBody</code>)를 원본 메시지 텍스트로 설정하고 <code>Body</code>를 결합된 프롬프트로 유지해야 합니다. 히스토리 버퍼는 <code>messages.groupChat.historyLimit</code> (전역 기본값) 및 <code>channels.slack.historyLimit</code> 또는 <code>channels.telegram.accounts.&lt;id&gt;.historyLimit</code> 같은 채널별 오버라이드 (<code>0</code>으로 비활성화)를 통해 구성할 수 있습니다.</p><h2 id="큐잉-및-후속-조치" tabindex="-1">큐잉 및 후속 조치 <a class="header-anchor" href="#큐잉-및-후속-조치" aria-label="Permalink to &quot;큐잉 및 후속 조치&quot;">​</a></h2><p>실행이 이미 활성 상태인 경우, 인바운드 메시지를 큐에 추가하거나, 현재 실행에 주입하거나, 후속 턴을 위해 수집할 수 있습니다.</p><ul><li><code>messages.queue</code> (및 <code>messages.queue.byChannel</code>)를 통해 구성합니다.</li><li>모드: <code>interrupt</code>, <code>steer</code>, <code>followup</code>, <code>collect</code>, 백로그 변형.</li></ul><p>세부사항: <a href="/openclaw-docs-ko/concepts/queue">큐잉</a>.</p><h2 id="스트리밍-청킹-배치" tabindex="-1">스트리밍, 청킹, 배치 <a class="header-anchor" href="#스트리밍-청킹-배치" aria-label="Permalink to &quot;스트리밍, 청킹, 배치&quot;">​</a></h2><p>블록 스트리밍은 모델이 텍스트 블록을 생성하면서 부분 응답을 전송합니다. 청킹은 채널 텍스트 한도를 준수하고 펜스드 코드 분리를 방지합니다.</p><p>주요 설정:</p><ul><li><code>agents.defaults.blockStreamingDefault</code> (<code>on|off</code>, 기본값 off)</li><li><code>agents.defaults.blockStreamingBreak</code> (<code>text_end|message_end</code>)</li><li><code>agents.defaults.blockStreamingChunk</code> (<code>minChars|maxChars|breakPreference</code>)</li><li><code>agents.defaults.blockStreamingCoalesce</code> (유휴 기반 배치)</li><li><code>agents.defaults.humanDelay</code> (블록 응답 사이의 인간적 일시정지)</li><li>채널 오버라이드: <code>*.blockStreaming</code> 및 <code>*.blockStreamingCoalesce</code> (Telegram 이외의 채널은 명시적인 <code>*.blockStreaming: true</code> 필요)</li></ul><p>세부사항: <a href="/openclaw-docs-ko/concepts/streaming">스트리밍 + 청킹</a>.</p><h2 id="추론-가시성-및-토큰" tabindex="-1">추론 가시성 및 토큰 <a class="header-anchor" href="#추론-가시성-및-토큰" aria-label="Permalink to &quot;추론 가시성 및 토큰&quot;">​</a></h2><p>OpenClaw는 모델 추론을 노출하거나 숨길 수 있습니다:</p><ul><li><code>/reasoning on|off|stream</code>이 가시성을 제어합니다.</li><li>추론 내용은 모델이 생성할 때 여전히 토큰 사용에 포함됩니다.</li><li>Telegram은 추론 스트림을 초안 버블에 지원합니다.</li></ul><p>세부사항: <a href="/openclaw-docs-ko/tools/thinking">사고 + 추론 지시어</a> 및 <a href="/openclaw-docs-ko/reference/token-use">토큰 사용</a>.</p><h2 id="접두사-스레딩-응답" tabindex="-1">접두사, 스레딩, 응답 <a class="header-anchor" href="#접두사-스레딩-응답" aria-label="Permalink to &quot;접두사, 스레딩, 응답&quot;">​</a></h2><p>아웃바운드 메시지 포맷팅은 <code>messages</code>에 중앙 집중됩니다:</p><ul><li><code>messages.responsePrefix</code>, <code>channels.&lt;channel&gt;.responsePrefix</code>, <code>channels.&lt;channel&gt;.accounts.&lt;id&gt;.responsePrefix</code> (아웃바운드 접두사 케스케이드), <code>channels.whatsapp.messagePrefix</code> (WhatsApp 인바운드 접두사)</li><li><code>replyToMode</code> 및 채널별 기본값을 통한 응답 스레딩</li></ul><p>세부사항: <a href="/openclaw-docs-ko/gateway/configuration-reference#messages">구성</a> 및 채널 문서.</p><h2 id="관련-항목" tabindex="-1">관련 항목 <a class="header-anchor" href="#관련-항목" aria-label="Permalink to &quot;관련 항목&quot;">​</a></h2><ul><li><a href="/openclaw-docs-ko/concepts/streaming">스트리밍</a> — 실시간 메시지 전달</li><li><a href="/openclaw-docs-ko/concepts/retry">재시도</a> — 메시지 전달 재시도 동작</li><li><a href="/openclaw-docs-ko/concepts/queue">큐</a> — 메시지 처리 큐</li><li><a href="/openclaw-docs-ko/channels/">채널</a> — 메시징 플랫폼 통합</li></ul>`,47)])])}const g=e(l,[["render",o]]);export{k as __pageData,g as default};
